from pathlib import Path
import ast

tests_dir = Path("tests")

def ensure_tests_dir():
    tests_dir.mkdir(exist_ok=True)

def set_permissions(path, mode):
    if mode is not None:
        os.chmod(path, int(mode, 8))

def discover_functions(source_dir):
    funcs = []
    for py_file in Path(source_dir).rglob("*.py"):
        if "tests" in py_file.parts:
            continue
        try:
            tree = ast.parse(py_file.read_text())
            for node in ast.walk(tree):
                if isinstance(node, ast.FunctionDef):
                    funcs.append(node.name)
        except Exception:
            pass
    return funcs

def existing_tests():
    names = set()
    for py_file in tests_dir.glob("test_*.py"):
        try:
            text = py_file.read_text()
            for line in text.splitlines():
                if line.startswith("def test_"):
                    names.add(line.split("(")[0].replace("def ", "").replace("test_", ""))
        except Exception:
            pass
    return names

def generate_test(test_name, perm=None):
    path = tests_dir / f"test_{test_name}.py"
    if path.exists():
        return
    with open(path, "w") as f:
        f.write(f"def test_{test_name}():\n    assert True\n")
    set_permissions(path, perm)

def main():
    parser = argparse.ArgumentParser(description="Dramatic coverage oracle!")
    parser.add_argument("--src", default=".", help="Source directory")
    parser.add_argument("--perm", default=None, help="Octal permissions for new tests, e.g. 644")
    args = parser.parse_args()

    ensure_tests_dir()
    funcs = discover_functions(args.src)
    tested = existing_tests()

    for fn in funcs:
        if fn not in tested:
            generate_test(fn, args.perm)

if __name__ == "__main__":
    main()

