def booking():
    flight_number = request.args.get("flight_number")
    departure_date = request.args.get("departure_date")
    return_date = request.args.get("return_date")
    passenger_name = request.args.get("passenger_name")

    # Validate required fields
    if not all([flight_number, departure_date, passenger_name]):
        return jsonify({"error": "Missing required parameters"}), 400

    dep_date_obj = validate_date(departure_date)
    ret_date_obj = validate_date(return_date) if return_date else None

    if not dep_date_obj:
        return jsonify({"error": "Invalid departure_date format. Use YYYY-MM-DD"}), 400
    if return_date and not ret_date_obj:
        return jsonify({"error": "Invalid return_date format. Use YYYY-MM-DD"}), 400
    if ret_date_obj and ret_date_obj < dep_date_obj:
        return jsonify({"error": "return_date cannot be earlier than departure_date"}), 400

    return jsonify({
        "flight_number": flight_number,
        "departure_date": departure_date,
        "return_date": return_date,
        "passenger_name": passenger_name,
        "status": "Booking details received"
    }), 200

